import pytest

def test_non_addendum_observation_rejected_on_closed_encounter(
    api_client, closed_encounter
):
    enc_id = closed_encounter["id"]
    obs_payload = {
        "resourceType": "Observation",
        "status": "final",
        "category": [{"coding": [{"code": "vital-signs"}]}],
        "encounter": {"reference": f"Encounter/{enc_id}"},
        "code": {"coding": [{"system": "http://loinc.org", "code": "8867-4"}]},
        "valueQuantity": {"value": 72, "unit": "bpm"}
    }

    resp = api_client.post("/Observation", json=obs_payload)
    assert resp.status_code in (409, 422), (
        f"Expected 409 or 422 for non-addendum write on closed encounter, got {resp.status_code}"
    )
